import org.mockito.internal.util.MockUtil;

import java.util.Date;

public class TestComparableFix {
    public static void main(String[] args) {
        try {
            // Create a mock Date object
            Date mockDate = Mockito.mock(Date.class);

            // Create ReturnsEmptyValues instance (this is what handles default answers)
            ReturnsEmptyValues returnsEmptyValues = new ReturnsEmptyValues();

            // Test 1: Compare mock to itself - should return 0
            System.out.println("Testing mock.compareTo(mock) - should return 0:");
            int result1 = mockDate.compareTo(mockDate); // This should invoke the ReturnsEmptyValues.answer method
            System.out.println("Result when comparing to itself: " + result1);

            // Test 2: Compare mock to different object - should return non-zero
            System.out.println("\nTesting mock.compareTo(different_object) - should return non-zero:");
            Date differentDate = Mockito.mock(Date.class);
            int result2 = mockDate.compareTo(differentDate);
            System.out.println("Result when comparing to different object: " + result2);

            // Verify results
            if (result1 == 0) {
                System.out.println("\n✅ SUCCESS: compareTo(mock, mock) returned 0 as expected");
            } else {
                System.out.println("\n❌ FAIL: compareTo(mock, mock) returned " + result1 + " instead of 0");
            }

            if (result2 != 0) {
                System.out.println("✅ SUCCESS: compareTo(mock, different) returned non-zero as expected");
            } else {
                System.out.println("❌ FAIL: compareTo(mock, different) returned 0 instead of non-zero");
            }

        } catch (Exception e) {
            System.out.println("Exception occurred: " + e.getMessage());
            e.printStackTrace();
        }
    }
}

